  /**
   * Builds the Price Code for a duplicated RFQ line by appending a `_DP_`
   * marker plus a random 5-char suffix to keep the code unique.
   *
   * Any existing `_DP_xxxxx` tail is stripped first, so repeatedly copying a
   * copy does not stack suffixes and grow the code without bound. The result
   * is always `<base>_DP_<5 chars>`, regardless of how many times the source
   * line has already been duplicated.
   */
  static buildDuplicatePriceCode(priceCode: string): string {
    const base = (priceCode ?? '').replace(/_DP_[A-Z0-9]{5}$/, '');
    return base + '_DP_' + Math.random().toString(36).slice(2, 7).toUpperCase();
  }
  private _filter(value: any, data): any[] {
