exports.STDVendorToRFQVendor = async (prodItems, RFQitem_id_fk) => {
  return (function () {
    let vendors = [];
    for (var u = 0; prodItems.length > u; u++) {

      let prodItem = prodItems[u];

      for (var i = 0; prodItem.StandardizedGroups.length > i; i++) {
        let stdGroup = prodItem.StandardizedGroups[i].dataValues;
        for (var j = 0; stdGroup.StandardizedSizes.length > j; j++) {

          let stdSize = stdGroup.StandardizedSizes[j].dataValues;

          for (var k = 0; stdSize.StandardizedDetails.length > k; k++) {
            let stdDetail = stdSize.StandardizedDetails[k].dataValues;

            for (var m = 0; stdDetail.StandardizedVendors.length > m; m++) {
              let stdVendor = stdDetail.StandardizedVendors[m].dataValues;
              vendors.push({});
              vendors[vendors.length - 1].RFQVendor_amount = stdVendor.price
              if (stdVendor.width && stdVendor.height && stdVendor.length && stdGroup.casePack) {
                vendors[vendors.length - 1].RFQVendor_cbm_pc = (((stdVendor.length * stdVendor.width * stdVendor.height) / 1000000) / stdGroup.casePack).toFixed(7);
              }
              vendors[vendors.length - 1].carton_width = stdVendor.width
              vendors[vendors.length - 1].carton_height = stdVendor.height
              vendors[vendors.length - 1].carton_length = stdVendor.length
              vendors[vendors.length - 1].RFQitem_id_fk = RFQitem_id_fk
              vendors[vendors.length - 1].vendor_id_fk = stdVendor.factory_id_fk
              vendors[vendors.length - 1].quote_date = stdVendor.quote_date
              vendors[vendors.length - 1].std_vendor_id_fk = stdVendor.pKey

            }
          }
        }
      }
    }
    return vendors;
  })();
}

function generatePriceCode() {
  let price_code = 'STD_';
  let randomStr = Math.random().toString(36).slice(2, 7).toUpperCase();
  let month = new Date().getMonth();
  let day = new Date().getDate();
  let hour = new Date().getHours();
  let minute = new Date().getMinutes();
  let millisecond = new Date().getMilliseconds();
  price_code += randomStr + month + day + "_" + hour + minute + millisecond;
  return price_code
}

