    const twice = DuplicateDialogComponent.buildDuplicatePriceCode(once);
    const thrice = DuplicateDialogComponent.buildDuplicatePriceCode(twice);

    expect(once).toMatch(COPY_CODE);
    expect(twice).toMatch(COPY_CODE);
    expect(thrice).toMatch(COPY_CODE);
    expect(thrice.length).toBe(9);
  });

